            ))}
            {/* Loading indicator */}
            {isStreaming && activeMessages[activeMessages.length - 1]?.role !== "assistant" && (
              <div style={{ ...styles.bubble, alignSelf: "flex-start" }}>
                <div style={styles.bubbleHeader}>Rules Scholar</div>
