                      <div style={styles.formGroup}>
                        <label style={styles.labelSmall}>Next Node</label>
                        <select
                          className="form-input"
                          value={choice.nextNodeId || ""}
                          onChange={(e) => handleChoiceFieldChange(i, "nextNodeId", e.target.value)}
