                        </label>

                        {choice.skillCheck && (
                          <div style={styles.skillCheckFields}>
                            <div style={styles.formGroup}>
                              <label style={styles.labelSmall}>Skill</label>
                              <select
                                className="form-input"
                                value={choice.skillCheck.type || "persuasion"}
