// Coin icon mapping
function CoinIcon({ type }) {
  const colors = {
    pp: "#e2e8f0",
    gp: "#fbbf24",
    ep: "#94a3b8",
    sp: "#cbd5e1",
    cp: "#b87333",
  };
  return (
    <span style={{
      display: "inline-block",
      width: "12px",
      height: "12px",
      borderRadius: "50%",
      background: colors[type] || "#999",
      border: "1px solid rgba(0,0,0,0.2)",
      marginRight: "2px",
    }} />
  );
}

function LootGeneratorPanel({ user }) {
  const { addToast } = useToast();
  const authHeaders = getAuthHeaders(user);
  const jsonAuthHeaders = getJsonAuthHeaders(user);

  // Generate form
  const [cr, setCr] = useState("1");
  const [lootType, setLootType] = useState("hoard");
  const [generating, setGenerating] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  // Cache
  const [activeTab, setActiveTab] = useState("generate");
  const [caches, setCaches] = useState([]);
  const [loadingCaches, setLoadingCaches] = useState(false);
  const [assigningId, setAssigningId] = useState(null);
  const [parties, setParties] = useState([]);
  const [selectedParty, setSelectedParty] = useState({});

  // Fetch parties
  const fetchParties = useCallback(async () => {
    try {
      const res = await fetch(PARTY_API, { headers: authHeaders });
      if (res.ok) {
        const data = await res.json();
        setParties(data);
        // Auto-select first party
        if (data.length > 0 && !selectedParty[0]) {
          setSelectedParty({ 0: data[0].id });
        }
      }
    } catch (err) {
      console.error("Failed to fetch parties:", err);
    }
  }, [authHeaders]);

  // Fetch caches
  const fetchCaches = useCallback(async () => {
    setLoadingCaches(true);
    try {
      const res = await fetch(`${API}/cache`, { headers: authHeaders });
      if (res.ok) {
        const data = await res.json();
        setCaches(data);
      }
    } catch (err) {
      console.error("Failed to fetch caches:", err);
    } finally {
      setLoadingCaches(false);
    }
  }, [authHeaders]);

  useEffect(() => {
    if (user) {
      fetchParties();
      fetchCaches();
    }
  }, [user, fetchParties, fetchCaches]);

  // Generate loot
  const handleGenerate = async () => {
    setGenerating(true);
    setError(null);
    setResult(null);
    try {
      const res = await fetch(`${API}/generate`, {
        method: "POST",
        headers: jsonAuthHeaders,
        body: JSON.stringify({ cr: parseFloat(cr) || 1, type: lootType }),
      });
      const data = await res.json();
      if (res.ok) {
        setResult(data);
      } else {
        setError(data.error || "Failed to generate loot.");
      }
    } catch (err) {
      setError(`Network error: ${err.message}`);
    } finally {
      setGenerating(false);
    }
  };

  // Keep as unclaimed
  const handleKeepUnclaimed = async () => {
    if (!result) return;
    try {
      const res = await fetch(`${API}/cache`, {
        method: "POST",
        headers: jsonAuthHeaders,
        body: JSON.stringify({
          label: result.label || `CR ${cr} ${lootType}`,
          data: result,
          totalValue: result.totalValue || 0,
          tier: result.tier || "",
        }),
      });
      if (res.ok) {
        addToast("Loot saved to unclaimed cache.", "success");
        setResult(null);
        fetchCaches();
      } else {
        const errData = await res.json();
        addToast(errData.error || "Failed to save loot.", "error");
      }
    } catch (err) {
      addToast(`Network error: ${err.message}`, "error");
    }
  };

  // Assign cache to party
  const handleAssignCache = async (cacheId) => {
    const partyId = selectedParty[cacheId];
    if (!partyId) {
      addToast("Please select a party first.", "warning");
      return;
    }
    setAssigningId(cacheId);
    try {
      const res = await fetch(`${API}/cache/${cacheId}/assign`, {
        method: "POST",
        headers: jsonAuthHeaders,
        body: JSON.stringify({ partyId }),
      });
      const data = await res.json();
      if (res.ok) {
        addToast(data.message || "Loot assigned to party!", "success");
        fetchCaches();
        fetchParties();
      } else {
        addToast(data.error || "Failed to assign loot.", "error");
      }
    } catch (err) {
      addToast(`Network error: ${err.message}`, "error");
    } finally {
      setAssigningId(null);
    }
  };

  // Discard cache
  const handleDiscardCache = async (cacheId) => {
    try {
      const res = await fetch(`${API}/cache/${cacheId}`, {
        method: "DELETE",
        headers: authHeaders,
      });
      if (res.ok) {
        addToast("Loot cache discarded.", "info");
        setCaches((prev) => prev.filter((c) => c.id !== cacheId));
      } else {
        const errData = await res.json();
        addToast(errData.error || "Failed to discard.", "error");
      }
    } catch (err) {
      addToast(`Network error: ${err.message}`, "error");
    }
  };

  // Render coins
  function renderCoins(coins) {
    if (!coins) return null;
    const entries = [
      { key: "pp", label: "PP", value: coins.pp },
      { key: "gp", label: "GP", value: coins.gp },
      { key: "ep", label: "EP", value: coins.ep },
      { key: "sp", label: "SP", value: coins.sp },
      { key: "cp", label: "CP", value: coins.cp },
    ].filter(e => e.value > 0);

    if (entries.length === 0) return <div style={{ color: "var(--color-muted)", fontSize: "0.85rem" }}>No coins</div>;

    return (
      <div style={STYLES.coinRow}>
        {entries.map(e => (
          <div key={e.key} style={STYLES.coinBadge}>
            <CoinIcon type={e.key} />
            <span>{e.value.toLocaleString()} {e.label}</span>
          </div>
        ))}
      </div>
    );
  }

  // Render item list
  function renderItemList(items, label, icon) {
    if (!items || items.length === 0) return null;
    return (
      <>
        <div style={STYLES.sectionTitle}>
          {icon}
          {label} ({items.length})
        </div>
        <ul style={STYLES.itemList}>
          {items.map((item, i) => (
            <li key={i} style={STYLES.itemEntry}>
              <span>{item.name}</span>
              <span style={{ color: "var(--color-muted)" }}>
                {item.value ? `${item.value} gp` : item.consumable ? "Consumable" : "Magic Item"}
              </span>
            </li>
          ))}
        </ul>
      </>
    );
  }

  // Render loot result
  function renderLootResult(data) {
    if (!data) return null;

    // Handle "both" type
    if (data.type === "both" && data.individual && data.hoard) {
      return (
        <div>
          <div style={{ ...STYLES.sectionTitle, fontSize: "1rem", marginTop: 0 }}>
            <Coins size={18} /> Individual Treasure
          </div>
          {renderCoins(data.individual.coins)}
          <div style={{ borderTop: "1px solid var(--color-border)", margin: "0.75rem 0" }} />
          <div style={{ ...STYLES.sectionTitle, fontSize: "1rem" }}>
            <Database size={18} /> Hoard Treasure
          </div>
          {renderCoins(data.hoard.coins)}
          {renderItemList(data.hoard.gems, "Gems", <Gem size={14} />)}
          {renderItemList(data.hoard.art, "Art Objects", <ScrollText size={14} />)}
          {renderItemList(data.hoard.magicItems, "Magic Items", <Sparkles size={14} />)}
          <div style={STYLES.totalBox}>
            Total Value: ~{data.totalValue?.toLocaleString()} gp
          </div>
        </div>
      );
    }

    const {coins} = data;
    const gems = data.gems || [];
    const art = data.art || [];
    const magicItems = data.magicItems || [];

    return (
      <div>
        {coins && renderCoins(coins)}
        {renderItemList(gems, "Gems & Gemstones", <Gem size={14} />)}
        {renderItemList(art, "Art Objects", <ScrollText size={14} />)}
        {renderItemList(magicItems, "Magic Items", <Sparkles size={14} />)}
        <div style={STYLES.totalBox}>
          Total Value: ~{data.totalValue?.toLocaleString()} gp
        </div>
      </div>
    );
  }

  // Main tabs
  const tabs = [
    { id: "generate", label: "Generate Loot", icon: <Sparkles size={14} /> },
    { id: "cache", label: `Unclaimed (${caches.length})`, icon: <Package size={14} /> },
  ];

  return (
    <div style={STYLES.panel}>
      <div style={STYLES.header}>
        <Coins size={22} />
        Loot Generator
      </div>

      {/* Tabs */}
      <div style={STYLES.tabs}>
        {tabs.map((tab) => (
          <button
            key={tab.id}
            style={{
              ...STYLES.tab,
              ...(activeTab === tab.id ? STYLES.tabActive : {}),
            }}
            onClick={() => setActiveTab(tab.id)}
            className="touch-target"
          >
            {tab.icon} {tab.label}
          </button>
        ))}
      </div>

      {activeTab === "generate" && (
        <div>
          {/* Generate Form */}
          <div style={STYLES.card}>
            <div style={STYLES.row}>
              <div>
                <label style={STYLES.label}>Challenge Rating</label>
                <input
                  type="number"
                  style={STYLES.input}
                  value={cr}
                  onChange={(e) => setCr(e.target.value)}
                  min="0"
                  max="30"
                  step="0.25"
                />
              </div>
              <div>
                <label style={STYLES.label}>Treasure Type</label>
                <select
                  style={STYLES.select}
                  value={lootType}
                  onChange={(e) => setLootType(e.target.value)}
                >
                  <option value="hoard">Hoard Treasure</option>
                  <option value="individual">Individual Treasure</option>
                  <option value="both">Both</option>
                </select>
              </div>
              <button
                style={{ ...STYLES.btn, ...STYLES.btnPrimary }}
                onClick={handleGenerate}
                disabled={generating}
              >
                {generating ? (
                  <Loader2 size={16} style={{ animation: "spin 1s linear infinite" }} />
                ) : (
                  <Sparkles size={16} />
                )}
                {generating ? "Generating..." : "Generate"}
              </button>
            </div>
          </div>

          {/* Error */}
          {error && <div style={STYLES.errorBox}>{error}</div>}

          {/* Result */}
          {result && (
            <div style={STYLES.card}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "0.75rem" }}>
                <div style={{ fontWeight: 600, fontSize: "1rem" }}>
                  {result.label || `CR ${cr} Treasure`}
                </div>
                <div style={{ fontSize: "0.8rem", color: "var(--color-muted)" }}>
                  {result.tier && `Tier ${result.tier}`}
                </div>
              </div>
              {renderLootResult(result)}
              <div style={{ display: "flex", gap: "0.5rem", marginTop: "1rem" }}>
                <button
                  style={{ ...STYLES.btn, ...STYLES.btnSuccess }}
                  onClick={handleKeepUnclaimed}
                >
                  <Package size={14} /> Keep Unclaimed
                </button>
                <button
                  style={{ ...STYLES.btn, ...STYLES.btnSecondary }}
                  onClick={handleGenerate}
                >
                  <RefreshCw size={14} /> Regenerate
                </button>
              </div>
            </div>
          )}

          {/* Quick info */}
          {!result && !error && (
            <div style={{ ...STYLES.card, ...STYLES.emptyState }}>
              <Coins size={32} style={{ opacity: 0.3, marginBottom: "0.5rem" }} />
              <div>Enter a Challenge Rating and select a treasure type,</div>
              <div>then click Generate to roll on the DMG treasure tables.</div>
            </div>
          )}
        </div>
      )}

      {activeTab === "cache" && (
        <div>
          {/* Unclaimed Caches List */}
          <div style={STYLES.card}>
            <div style={{ fontWeight: 600, marginBottom: "0.5rem", fontSize: "0.9rem" }}>
              Unclaimed Loot ({caches.length})
            </div>
            {loadingCaches ? (
              <div style={STYLES.emptyState}>
                <Loader2 size={20} style={{ animation: "spin 1s linear infinite" }} />
              </div>
            ) : caches.length === 0 ? (
              <div style={STYLES.emptyState}>
                <Package size={24} style={{ opacity: 0.3, marginBottom: "0.5rem" }} />
                <div>No unclaimed loot.</div>
                <div style={{ fontSize: "0.8rem" }}>Generate loot and save it here to assign later.</div>
              </div>
            ) : (
              caches.map((cache) => {
                const data = cache.data || {};
                const totalValue = cache.totalValue || data.totalValue || 0;
                const coins = data.coins || {};
                const gemCount = (data.gems || []).length;
                const artCount = (data.art || []).length;
                const magicItemCount = (data.magicItems || []).length;

                return (
                  <div key={cache.id} style={STYLES.cacheItem}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 500, fontSize: "0.9rem" }}>
                        {cache.label || "Unnamed Loot"}
                      </div>
                      <div style={{ fontSize: "0.8rem", color: "var(--color-muted)" }}>
                        {cache.tier && `Tier ${cache.tier} · `}
                        ~{totalValue.toLocaleString()} gp
                        {coins.gp > 0 && ` · ${coins.gp} gp`}
                        {gemCount > 0 && ` · ${gemCount} gem(s)`}
                        {artCount > 0 && ` · ${artCount} art`}
                        {magicItemCount > 0 && ` · ${magicItemCount} magic`}
                      </div>
                    </div>
                    <div style={{ display: "flex", gap: "0.3rem", alignItems: "center", flexWrap: "wrap" }}>
                      {parties.length > 0 && (
                        <>
                          <select
                            style={{ ...STYLES.select, width: "auto", fontSize: "0.8rem", padding: "0.3rem" }}
                            value={selectedParty[cache.id] || ""}
                            onChange={(e) => setSelectedParty(prev => ({ ...prev, [cache.id]: parseInt(e.target.value, 10) }))}
                          >
                            <option value="">Party...</option>
                            {parties.map((p) => (
                              <option key={p.id} value={p.id}>{p.name}</option>
                            ))}
                          </select>
                          <button
                            style={{ ...STYLES.btn, ...STYLES.btnSuccess, fontSize: "0.8rem", padding: "0.3rem 0.6rem" }}
                            onClick={() => handleAssignCache(cache.id)}
                            disabled={assigningId === cache.id}
                          >
                            {assigningId === cache.id ? (
                              <Loader2 size={12} style={{ animation: "spin 1s linear infinite" }} />
                            ) : (
                              <ArrowRight size={12} />
                            )}
                            Assign
                          </button>
                        </>
                      )}
                      <button
                        style={{ ...STYLES.btn, ...STYLES.btnDanger, fontSize: "0.8rem", padding: "0.3rem 0.6rem" }}
                        onClick={() => handleDiscardCache(cache.id)}
                      >
                        <Trash2 size={12} />
                      </button>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      )}

      {/* Spin animation */}
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

export default LootGeneratorPanel;

// =============================================================================
// Tablecast Virtual Tabletop (VTT) Engine — Orchestrator
// Decomposed into: MapConstants, useMapData, useMapInteraction,
// MapCanvas, MapToolbar, MapEncounterControls, MapModals, MapTokenDetails
// =============================================================================
import { useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import {
  AlertCircle, Plus, Trash2, X, UserPlus, Undo2, Grid3x3, Eye,
} from "lucide-react";
import { useSocket } from "../context/SocketContext";
import { useToast } from "../context/ToastContext";
import { useConfirm } from "../context/ConfirmContext";

import useMapData from "./map/useMapData";
import useMapInteraction from "./map/useMapInteraction";
import MapCanvas from "./map/MapCanvas";
import MapToolbar from "./map/MapToolbar";
import MapEncounterControls from "./map/MapEncounterControls";
import MapModals from "./map/MapModals";
import MapTokenDetails from "./map/MapTokenDetails";

export default function MapPanel({ user, isPopout = false }) {
  const { socket, isConnected } = useSocket();
  const { addToast } = useToast();
  const { showConfirm } = useConfirm();

  // ---- Route-driven map selection ----
  const { id: routeMapId } = useParams();
  const navigate = useNavigate();

  // ---- All state, data, and action handlers ----
  const D = useMapData({ user, isPopout, socket, isConnected, addToast, showConfirm, initialMapId: routeMapId ? Number(routeMapId) : null });

  // ---- Interaction handlers (zoom, pan, drag, touch) ----
  const interaction = useMapInteraction({
    tool: D.tool,
    zoom: D.zoom,
    panOffset: D.panOffset,
    isDrawing: D.isDrawing,
    isPanning: D.isPanning,
    panStart: D.panStart,
    dragState: D.dragState,
    currentPolygon: D.currentPolygon,
    tokens: D.tokens,
    gridSize: D.gridSize,
    user,
    isDM: D.isDM,
    activeMap: D.activeMap,
    setZoom: D.setZoom,
    setPanOffset: D.setPanOffset,
    setSelectedTokenId: D.setSelectedTokenId,
    setDragState: D.setDragState,
    setIsPanning: D.setIsPanning,
    setPanStart: D.setPanStart,
    setIsDrawing: D.setIsDrawing,
    setCurrentPolygon: D.setCurrentPolygon,
    setMousePosWorld: D.setMousePosWorld,
    canvasRef: D.canvasRef,
    imageRef: D.imageRef,
    gestureRef: D.gestureRef,
    pendingMovesRef: D.pendingMovesRef,
    socket,
    isConnected,
    setTokens: D.setTokens,
  });

  // Wrap handleStart to inject ruler click handler
  const handleStartWithRuler = (clientX, clientY) => {
    interaction.handleStart(clientX, clientY, { onRulerClick: D.handleRulerClick });
  };
  const handleTouchStartWithRuler = (e) => {
    // For ruler, we intercept touch start
    if (D.tool === "ruler" && e.touches.length === 1) {
      const t = e.touches[0];
      D.handleRulerClick(
        (t.clientX - D.panOffset.x) / D.zoom,
        (t.clientY - D.panOffset.y) / D.zoom
      );
      e.preventDefault();
      return;
    }
    interaction.handleTouchStart(e);
  };

  // ---- Derived ----
  const { gridSize, authHeaders, jsonAuthHeaders, withUser, isDM } = D;

  // ---------------------------------------------------------------------------
  // Render
  // ---------------------------------------------------------------------------
  return (
    <div style={styles.container} className="fade-in">
      {/* VTT Header */}
      <header style={styles.header}>
        <div style={styles.headerTitleBox}>
          <h2 style={styles.title}>Tacticians Grid</h2>
          {D.activeMap && (
            <span style={styles.mapNameBadge}>
              Active: {D.activeMap.name} ({D.activeMap.gridSize}px Grid)
            </span>
          )}
        </div>

        <div style={styles.headerControls}>
          <div style={styles.dmMapSelector}>
            <select
              value={D.activeMap?.id || ""}
              onChange={(e) => {
                const mapId = Number(e.target.value);
                D.handleSelectMap(mapId);
                if (!isPopout) navigate(`/dm/map/${mapId}`);
              }}
              style={styles.select}
              className="form-input touch-target"
              aria-label="Select map"
            >
              {D.mapsList.map((m) => (
                <option key={m.id} value={m.id}>{m.name}</option>
              ))}
            </select>
            {isDM && (
              <>
                <button onClick={() => D.setShowAddMapModal(true)} style={styles.btnSmall} className="btn-hover-scale glass-panel touch-target">
                  <Plus size={16} />
                  <span>New Map</span>
                </button>
                <button onClick={D.handleDeleteMap} style={styles.btnDangerSmall} className="btn-hover-scale glass-panel touch-target" disabled={!D.activeMap}>
                  <Trash2 size={16} />
                  <span>Delete</span>
                </button>
              </>
            )}
          </div>

          <span style={styles.status}>
            {isConnected ? "Live Sync" : "Offline Mode"}
          </span>
        </div>
      </header>

      {/* Error banner */}
      {D.loadError && !D.showAddMapModal && (
        <div style={styles.errorBanner}>
          <AlertCircle size={16} />
          <span>{D.loadError}</span>
          <button onClick={() => D.setLoadError(null)} style={styles.errorDismiss} className="touch-target">
            <X size={14} />
          </button>
        </div>
      )}

      {/* Main Grid/Map Arena Workspace */}
      <div
        ref={D.containerRef}
        style={styles.vttWorkspace}
        className="glass-panel gold-border-glow"
        onDragOver={D.handleDragOver}
        onDragLeave={D.handleDragLeave}
        onDrop={D.handleDrop}
      >
        {/* Drop zone overlay */}
        {(D.isDragOver || D.isDropProcessing) && (
          <div style={styles.dropZoneOverlay} className="glass-panel">
            <div style={styles.dropZoneContent}>
              <div style={styles.dropZoneIcon}>
