  const handleUndoFog = () => {
    if (!activeMap || !isDM) return;
    const polys = parseFogState(activeMap.fogState);
    if (polys.length === 0) return;
    const updated = polys.slice(0, polys.length - 1);
    if (socket && isConnected) socket.emit("fog:update", withUser({ mapId: activeMap.id, fogState: updated }));
  };

  const handleClearFog = (revealAll) => {
    if (!activeMap || !isDM) return;
    let updated = [];
    if (revealAll) {
      const imgW = imageRef.current ? imageRef.current.width : 2000;
      const imgH = imageRef.current ? imageRef.current.height : 2000;
      updated = [{ type: "reveal", points: [{ x: 0, y: 0 }, { x: imgW, y: 0 }, { x: imgW, y: imgH }, { x: 0, y: imgH }] }];
    }
    if (socket && isConnected) socket.emit("fog:update", withUser({ mapId: activeMap.id, fogState: updated }));
  };

  const handleFinishFogPolygon = () => {
    if (!activeMap) { setCurrentPolygon([]); setIsDrawing(false); return; }
    if (currentPolygon.length > 2) {
      const newPoly = { type: tool === "draw-fog" ? "hide" : "reveal", points: currentPolygon };
      const parsedFog = parseFogState(activeMap.fogState);
      const updatedFog = [...parsedFog, newPoly];
      if (socket && isConnected) {
        socket.emit("fog:update", { userId: user?.id, mapId: activeMap.id, fogState: JSON.stringify(updatedFog) });
      }
      setCurrentPolygon([]);
      setIsDrawing(false);
    }
  };

  // -- AI Encounter Builder --
  async function handleBuildEncounter() {
    const levels = encounterBuilderLevels.split(",").map((s) => Number(s.trim())).filter((n) => Number.isInteger(n) && n > 0);
    if (!levels.length) { setEncounterBuilderError("Enter at least one party level (e.g., 3, 5, 7)."); return; }
    setEncounterBuilderLoading(true);
    setEncounterBuilderError(null);
    setEncounterBuilderProgress("Consulting your monster database...");

    try {
      const res = await fetch("/api/ai/build-encounter", {
        method: "POST",
        headers: jsonAuthHeaders,
        body: JSON.stringify({ partyLevels: levels, difficulty: encounterBuilderDifficulty, context: encounterBuilderContext.trim() }),
      });
      if (!res.ok) { const err = await res.json().catch(() => ({})); throw new Error(err.error || "Failed to build encounter."); }
      const data = await res.json();
      if (data.encounter) { setEncounterBuilderResult(data.encounter); } else { throw new Error("No encounter data received."); }
    } catch (err) { setEncounterBuilderError(err.message); }
    finally { setEncounterBuilderLoading(false); setEncounterBuilderProgress(""); }
  }

  async function handleApplyEncounterResult() {
    if (!encounterBuilderResult || !activeMap) return;
    setEncounterBuilderLoading(true);
    try {
      const encRes = await fetch("/api/encounters", {
        method: "POST",
        headers: jsonAuthHeaders,
        body: JSON.stringify({ name: encounterBuilderResult.name || "AI Generated Encounter", mapId: activeMap.id }),
      });
      if (!encRes.ok) throw new Error("Failed to create encounter.");
      const encounter = await encRes.json();
      setActiveEncounter(encounter);

      for (const p of (encounterBuilderResult.participants || [])) {
        if (p.type === "monster") {
          try {
            const searchRes = await fetch(`/api/monsters?search=${encodeURIComponent(p.name)}`, { headers: authHeaders });
            if (searchRes.ok) {
              const monsters = await searchRes.json();
              const monster = monsters.find((m) => m.name.toLowerCase() === p.name.toLowerCase()) || monsters[0];
              if (monster) {
                for (let i = 0; i < (p.quantity || 1); i++) {
                  await fetch(`/api/encounters/${encounter.id}/participants`, {
                    method: "POST",
                    headers: jsonAuthHeaders,
                    body: JSON.stringify({ monsterId: monster.id, isHidden: false }),
                  });
                }
              }
            }
          } catch (e) { /* skip if monster not found */ }
        } else if (p.type === "npc") {
          try {
            const matchedNpc = availableNpcs.find((npc) => npc.name.toLowerCase() === String(p.name || "").toLowerCase());
            if (matchedNpc) {
              await fetch(`/api/encounters/${encounter.id}/participants`, {
                method: "POST",
                headers: jsonAuthHeaders,
                body: JSON.stringify({ npcId: matchedNpc.id, isHidden: false, type: "npc" }),
              });
            }
          } catch (e) { /* skip if NPC not found */ }
        }
      }
      setShowEncounterBuilder(false);
      setEncounterBuilderResult(null);
      loadActiveEncounter(activeMap.id);
    } catch (err) { setEncounterBuilderError(err.message); }
    finally { setEncounterBuilderLoading(false); setEncounterBuilderProgress(""); }
  }

  async function handleGenerateEncounterName() {
    if (!activeEncounter?.participants?.length) return;
    setEncounterBuilderLoading(true);
    setEncounterBuilderError(null);
    try {
      const participants = activeEncounter.participants.map((p) => ({ name: p.name || "Unknown", type: p.type || p.source || "unknown", cr: "?" }));
      const res = await fetch("/api/ai/encounter-description", {
        method: "POST",
        headers: jsonAuthHeaders,
        body: JSON.stringify({ participants }),
      });
      if (!res.ok) { const err = await res.json().catch(() => ({})); throw new Error(err.error || "Failed to generate name."); }
      const data = await res.json();
      if (data.name) {
        const updateRes = await fetch(`/api/encounters/${activeEncounter.id}`, { method: "PATCH", headers: jsonAuthHeaders, body: JSON.stringify({ name: data.name }) });
        if (updateRes.ok) { const updated = await updateRes.json(); setActiveEncounter(updated); }
      }
    } catch (err) { console.error("AI Name generation failed:", err); }
    finally { setEncounterBuilderLoading(false); }
  }

  // ---------------------------------------------------------------------------
  // Return all state and handlers
  // ---------------------------------------------------------------------------
  return {
    // State
    mapsList, activeMap, tokens, availableCharacters, availableNpcs, availableMonsters,
    activeEncounter, showEncounterDrawer, encounterName, encounterMonsterQuery,
    encounterMonster, encounterQuantity, encounterHidden, encounterNpcId, encounterCharacterId,
    encounterDeployX, encounterDeployY, encounterBusy,
    showEncounterBuilder, encounterBuilderLevels, encounterBuilderDifficulty,
    encounterBuilderContext, encounterBuilderLoading, encounterBuilderError,
    encounterBuilderResult, encounterBuilderProgress, loadError, isCreatingMap,
    tool, showGrid, zoom, panOffset, selectedTokenId,
    isDrawing, currentPolygon, mousePosWorld,
    rulerPoints, rulerHoverPos,
    showLighting,
    isPanning, panStart, dragState,
    showAddMapModal, showAddTokenModal,
    isDragOver, isDropProcessing, showGridSizePrompt, pendingMapId, newDropGridSize,
    newMapName, newMapGridSize, newMapFile, newMapImagePath,
    newTokenLabel, newTokenCharacterId, newTokenNpcId, newTokenMonsterId,
    newTokenImageUrl, newTokenIsMonster, newTokenStats, tokenType,
    mapImageLoaded, gridSize,

    // Refs
    containerRef, canvasRef, imageRef, tokenImagesRef, gestureRef,
    activeMapRef, selectedTokenIdRef, currentFetchIdRef, drawRafIdRef,
    pendingMovesRef, triggerRedrawRef,

    // Derived
    authHeaders, jsonAuthHeaders, withUser, isDM, pings,

    // Setters
    setMapsList, setActiveMap, setTokens, setActiveEncounter,
    setShowEncounterDrawer, setEncounterName, setEncounterMonsterQuery,
    setEncounterMonster, setEncounterQuantity, setEncounterHidden,
    setEncounterNpcId, setEncounterCharacterId, setEncounterDeployX, setEncounterDeployY,
    setEncounterBusy,
    setShowEncounterBuilder, setEncounterBuilderLevels, setEncounterBuilderDifficulty,
    setEncounterBuilderContext, setEncounterBuilderLoading, setEncounterBuilderError,
    setEncounterBuilderResult, setEncounterBuilderProgress, setLoadError, setIsCreatingMap,
    setTool, setShowGrid, setZoom, setPanOffset, setSelectedTokenId,
    setIsDrawing, setCurrentPolygon, setMousePosWorld,
    setRulerPoints, setRulerHoverPos,
    setShowLighting,
    setIsPanning, setPanStart, setDragState, setPings,
    setShowAddMapModal, setShowAddTokenModal,
    setIsDragOver, setShowGridSizePrompt, setPendingMapId, setNewDropGridSize,
    setNewMapName, setNewMapGridSize, setNewMapFile, setNewMapImagePath,
    setNewTokenLabel, setNewTokenCharacterId, setNewTokenNpcId, setNewTokenMonsterId,
    setNewTokenImageUrl, setNewTokenIsMonster, setNewTokenStats, setTokenType,
    setMapImageLoaded,

    // Action handlers
    loadMaps, loadCharacters, loadNpcs, loadMonsters, fetchMapDetails,
    loadActiveEncounter, resetViewport, persistEncounterResult,
    handleSelectMap, handleMapPresetSelect, handleCancelAddMap, handleCreateMap, handleDeleteMap,
    handleTokenPresetSelect, resolveMonsterTokenImage, handleQuickCharacterToken,
    handleCreateToken, handleDeleteToken,
    handleCreateEncounter, handleAddMonsterToEncounter, handleAddNpcToEncounter,
    handleAddCharacterToEncounter, handleDeployEncounter, handleStartEncounter,
    handleAdvanceEncounterTurn, handleCompleteEncounter, handleParticipantHp,
    handleNpcRoll, handleMonsterRoll,
    handleRulerClick, handleRulerUndo, handleRulerClear,
    handleUndoFog, handleClearFog, handleFinishFogPolygon,
    handleDragOver, handleDragLeave, handleDrop,
    handleConfirmGridSize, handleCancelGridSize,
    handleBuildEncounter, handleApplyEncounterResult, handleGenerateEncounterName,
  };
}

// =============================================================================
// useMapInteraction — Zoom, pan, drag, touch/gesture handlers
// =============================================================================
import { useRef, useCallback } from "react";
import { MIN_ZOOM, MAX_ZOOM, DRAG_THRESHOLD_PX } from "./MapConstants";
import { canMoveToken } from "../../utils/authHeaders";

export default function useMapInteraction({
  // State values
  tool, zoom, panOffset, isDrawing, isPanning, panStart, dragState, currentPolygon,
  tokens, gridSize, user, isDM, activeMap,
  // Setters
  setZoom, setPanOffset, setSelectedTokenId, setDragState,
  setIsPanning, setPanStart, setIsDrawing, setCurrentPolygon, setMousePosWorld,
  // Refs
  canvasRef, imageRef, gestureRef, pendingMovesRef,
  // Socket
  socket, isConnected, setTokens,
}) {
  const longPressTimerRef = useRef(null);
  const longPressPosRef = useRef(null);

  const getWorldCoordinates = useCallback((clientX, clientY) => {
    const canvas = canvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const screenX = clientX - rect.left;
    const screenY = clientY - rect.top;

    return {
      x: (screenX - panOffset.x) / zoom,
      y: (screenY - panOffset.y) / zoom,
      screenX,
      screenY,
    };
  }, [canvasRef, panOffset, zoom]);

  const getTouchDistance = (touches) => {
    const dx = touches[0].clientX - touches[1].clientX;
    const dy = touches[0].clientY - touches[1].clientY;
    return Math.hypot(dx, dy);
  };

  const getTouchMidpoint = (touches) => ({
    clientX: (touches[0].clientX + touches[1].clientX) / 2,
    clientY: (touches[0].clientY + touches[1].clientY) / 2,
  });

  const applyZoomAt = useCallback((nextZoom, clientX, clientY) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const screenX = clientX - rect.left;
    const screenY = clientY - rect.top;
    const clampedZoom = Math.max(MIN_ZOOM, Math.min(nextZoom, MAX_ZOOM));
    const worldX = (screenX - panOffset.x) / zoom;
    const worldY = (screenY - panOffset.y) / zoom;

    setZoom(clampedZoom);
    setPanOffset({
      x: screenX - worldX * clampedZoom,
      y: screenY - worldY * clampedZoom,
    });
  }, [canvasRef, panOffset, zoom, setZoom, setPanOffset]);

  const handleStart = useCallback((clientX, clientY, options = {}) => {
    const { x, y, screenX, screenY } = getWorldCoordinates(clientX, clientY);
    setMousePosWorld({ x, y });

    if (tool === "ruler") {
      // Ruler tool: add a point on each click, pass handler from parent via options
      if (options.onRulerClick) {
        options.onRulerClick(x, y);
      }
      return;
    }

    if (tool === "select") {
      const hitToken = tokens.find(token => {
        const tx = (token.x + 0.5) * gridSize;
        const ty = (token.y + 0.5) * gridSize;
        const radius = gridSize * 0.42;
        const dx = x - tx;
        const dy = y - ty;
        return dx * dx + dy * dy < radius * radius;
      });

      if (hitToken) {
        const isOwner = canMoveToken(hitToken, user, false);
        if (isDM || isOwner) {
          setSelectedTokenId(hitToken.id);
          setDragState({
            tokenId: hitToken.id,
            startGridPos: { x: hitToken.x, y: hitToken.y },
            currentWorldPos: { x: (hitToken.x + 0.5) * gridSize, y: (hitToken.y + 0.5) * gridSize },
            startScreenPos: { x: screenX, y: screenY },
            pending: options.isTouch === true,
            offset: {
              x: x - (hitToken.x + 0.5) * gridSize,
              y: y - (hitToken.y + 0.5) * gridSize,
            },
          });
        }
      } else {
        setIsPanning(true);
        setSelectedTokenId(null);
        setPanStart({
          x: screenX - panOffset.x,
          y: screenY - panOffset.y,
        });
      }
    } else if (tool === "draw-fog" || tool === "reveal-fog") {
      if (user?.role === "DM" && activeMap) {
        setIsDrawing(true);
        setCurrentPolygon(prev => [...prev, { x, y }]);
      }
    }

    // Start long-press timer for ping (touch only)
    if (options.isTouch === true) {
      longPressPosRef.current = { x: clientX, y: clientY };
      longPressTimerRef.current = setTimeout(() => {
        const { x: wx, y: wy } = getWorldCoordinates(clientX, clientY);
        if (socket && isConnected && activeMap) {
          const col = Math.round(wx / gridSize - 0.5);
          const row = Math.round(wy / gridSize - 0.5);
          socket.emit("token:ping", {
            mapId: activeMap.id,
            x: col,
            y: row,
            type: "look",
            userId: user?.id,
            sender: user?.username || "Player",
          });
        }
        longPressTimerRef.current = null;
      }, 500);
    }
  }, [getWorldCoordinates, tool, tokens, gridSize, user, isDM, activeMap,
      setMousePosWorld, setSelectedTokenId, setDragState, setIsPanning,
      setPanStart, setIsDrawing, setCurrentPolygon, panOffset,
      socket, isConnected]);

  const handleMove = useCallback((clientX, clientY) => {
    const { x, y, screenX, screenY } = getWorldCoordinates(clientX, clientY);

    if (isDrawing) {
      setMousePosWorld({ x, y });
    }

      if (dragState) {
        setDragState(prev => {
          if (prev.pending) {
            const dx = screenX - prev.startScreenPos.x;
            const dy = screenY - prev.startScreenPos.y;
            if (Math.hypot(dx, dy) < DRAG_THRESHOLD_PX) return prev;
          }

          return {
          ...prev,
          pending: false,
          currentWorldPos: {
            x: x - prev.offset.x,
            y: y - prev.offset.y,
          },
        };
      });
    } else if (isPanning) {
      setPanOffset({
        x: screenX - panStart.x,
        y: screenY - panStart.y,
      });
    }

    // Cancel long-press if pointer moved too far
    if (longPressTimerRef.current && longPressPosRef.current) {
      const dx = clientX - longPressPosRef.current.x;
      const dy = clientY - longPressPosRef.current.y;
      if (Math.hypot(dx, dy) > 10) {
        clearTimeout(longPressTimerRef.current);
        longPressTimerRef.current = null;
        longPressPosRef.current = null;
      }
    }
  }, [getWorldCoordinates, isDrawing, dragState, isPanning, panStart,
      setMousePosWorld, setDragState, setPanOffset]);

  const handleEnd = useCallback(() => {
    if (dragState) {
      if (dragState.pending) {
        setDragState(null);
        return;
      }

      const px = dragState.currentWorldPos.x;
      const py = dragState.currentWorldPos.y;

      const col = Math.round(px / gridSize - 0.5);
      const row = Math.round(py / gridSize - 0.5);

      const imgW = imageRef.current ? imageRef.current.width : 1000;
      const imgH = imageRef.current ? imageRef.current.height : 800;
      const maxCol = Math.max(0, Math.floor(imgW / gridSize) - 1);
      const maxRow = Math.max(0, Math.floor(imgH / gridSize) - 1);

      const clampedCol = Math.max(0, Math.min(col, maxCol));
      const clampedRow = Math.max(0, Math.min(row, maxRow));

      if (socket && isConnected) {
        socket.emit("token:move", {
          userId: user?.id,
          id: dragState.tokenId,
          x: clampedCol,
          y: clampedRow,
        });
      } else {
        setTokens(prev => prev.map(t =>
          t.id === dragState.tokenId ? { ...t, x: clampedCol, y: clampedRow } : t
        ));
        if (pendingMovesRef) {
          pendingMovesRef.current.push({
            tokenId: dragState.tokenId,
            x: clampedCol,
            y: clampedRow,
          });
        }
      }

      setDragState(null);
    }

    if (isPanning) {
      setIsPanning(false);
    }

    // Cancel long-press on quick tap
    if (longPressTimerRef.current) {
      clearTimeout(longPressTimerRef.current);
      longPressTimerRef.current = null;
    }
    longPressPosRef.current = null;
  }, [dragState, isPanning, gridSize, imageRef, socket, isConnected, user,
      setDragState, setIsPanning, setTokens, pendingMovesRef]);

  const handleTouchStart = useCallback((e) => {
    e.preventDefault();

    if (e.touches.length === 2) {
      const midpoint = getTouchMidpoint(e.touches);
      gestureRef.current = {
        type: "pinch",
        startDistance: getTouchDistance(e.touches),
        startZoom: zoom,
        midpoint,
      };
      setDragState(null);
      setIsPanning(false);
      return;
    }

    if (e.touches.length === 1) {
      const t = e.touches[0];
      gestureRef.current = null;
      handleStart(t.clientX, t.clientY, { isTouch: true });
    }
  }, [zoom, gestureRef, setDragState, setIsPanning, handleStart]);

  const handleTouchMove = useCallback((e) => {
    e.preventDefault();

    if (e.touches.length === 2 && gestureRef.current?.type === "pinch") {
      const distance = getTouchDistance(e.touches);
      const midpoint = getTouchMidpoint(e.touches);
      const nextZoom = gestureRef.current.startZoom * (distance / gestureRef.current.startDistance);
      applyZoomAt(nextZoom, midpoint.clientX, midpoint.clientY);
      return;
    }

    if (e.touches.length === 1) {
      const t = e.touches[0];
      handleMove(t.clientX, t.clientY);
    }
  }, [gestureRef, applyZoomAt, handleMove]);

  const handleTouchEnd = useCallback((e) => {
    e.preventDefault();

    // Cancel long-press on touch end
    if (longPressTimerRef.current) {
      clearTimeout(longPressTimerRef.current);
      longPressTimerRef.current = null;
    }

    if (e.touches.length === 0) {
      gestureRef.current = null;
      handleEnd();
    } else if (e.touches.length === 1) {
      const t = e.touches[0];
      gestureRef.current = null;
      handleStart(t.clientX, t.clientY, { isTouch: true });
    }
  }, [gestureRef, handleEnd, handleStart]);

  const handleZoom = useCallback((amount) => {
    const canvas = canvasRef.current;
    if (!canvas) {
      setZoom(prev => Math.max(MIN_ZOOM, Math.min(prev + amount, MAX_ZOOM)));
      return;
    }
    const rect = canvas.getBoundingClientRect();
    applyZoomAt(zoom + amount, rect.left + rect.width / 2, rect.top + rect.height / 2);
  }, [canvasRef, zoom, setZoom, applyZoomAt]);

  const fitView = useCallback(() => {
    if (imageRef.current) {
      const imgW = imageRef.current.width;
      const imgH = imageRef.current.height;
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rect = canvas.getBoundingClientRect();
      const fitZoom = Math.min(rect.width / imgW, rect.height / imgH) * 0.9;
      const clampedZoom = Math.max(MIN_ZOOM, Math.min(fitZoom, MAX_ZOOM));
      setZoom(clampedZoom);
      setPanOffset({
        x: (rect.width - imgW * clampedZoom) / 2,
        y: (rect.height - imgH * clampedZoom) / 2,
      });
    }
  }, [imageRef, canvasRef, setZoom, setPanOffset]);

  return {
    handleStart,
    handleMove,
    handleEnd,
    handleTouchStart,
    handleTouchMove,
    handleTouchEnd,
    handleZoom,
    fitView,
    applyZoomAt,
    getWorldCoordinates,
  };
}

// =============================================================================
// Tablecast — Session Detail Component
// Self-contained detail view for a single campaign session: agenda, prep
// checklist, linked resources, recap, and lifecycle management.
// =============================================================================
import { useState } from "react";
import {
  ArrowLeft,
  Check,
  Eye,
  EyeOff,
  Link2,
  Plus,
  Trash2,
  X,
} from "lucide-react";
import AiAssistButton, { AI_FIELD_ACTIONS } from "../AiAssistButton";
import { sessionStyles } from "./sessionStyles";
import {
  compileMarkdown,
  parseJson,
  parseIdArray,
  formatDate,
  toDateInputValue,
  checklistProgress,
  statusStyle,
} from "./sessionUtils";

export default function SessionDetail({
  selectedSession,
  saving,
  error,
  isDm,
  user,
  authHeaders,
  navigate,
  basePath,
  wikiById,
  mapById,
  encounterById,
  wikiArticles,
  maps,
  encounters,
  onUpdateField,
  onPatchSession,
  onDeleteSession,
  onSetError,
  onSetSaving,
  onSessionSynced,
  showConfirm,
}) {
  /* ---- local UI state ---- */
  const [showPreview, setShowPreview] = useState(false);
  const [newChecklistItem, setNewChecklistItem] = useState("");
  const [publishMessage, setPublishMessage] = useState(null);
  const [aiSessionLoading, setAiSessionLoading] = useState(false);
  const [aiSessionProgress, setAiSessionProgress] = useState("");
  const [aiSessionError, setAiSessionError] = useState(null);

  if (!selectedSession) return null;

  /* ---- helpers ---- */
  function getChecklistItems() {
    return parseJson(selectedSession?.prepChecklist, []);
  }

  async function saveChecklist(items) {
    await onPatchSession({ prepChecklist: JSON.stringify(items) });
  }

  async function handleAddChecklistItem(e) {
    e.preventDefault();
    const text = newChecklistItem.trim();
    if (!text) return;
    const items = [
      ...getChecklistItems(),
      { id: `item-${Date.now()}`, text, done: false },
    ];
    setNewChecklistItem("");
    await saveChecklist(items);
  }

  async function handleToggleChecklistItem(itemId) {
    const items = getChecklistItems().map((item) =>
      item.id === itemId ? { ...item, done: !item.done } : item
    );
    await saveChecklist(items);
  }

  async function handleRemoveChecklistItem(itemId) {
    const items = getChecklistItems().filter((item) => item.id !== itemId);
    await saveChecklist(items);
  }

  async function toggleLinkedId(field, id) {
    const current = parseIdArray(selectedSession[field]);
    const next = current.includes(id)
      ? current.filter((value) => value !== id)
      : [...current, id];
    await onPatchSession({ [field]: JSON.stringify(next) });
  }

  async function handlePublishRecap() {
    if (!selectedSession) return;
    try {
      onSetSaving(true);
      onSetError(null);
      setPublishMessage(null);
      const res = await fetch(`/api/sessions/${selectedSession.id}/publish-recap`, {
        method: "POST",
        headers: authHeaders,
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.error || "Failed to publish recap.");
      }
      const data = await res.json();
      if (data.session) {
        onSessionSynced(data.session);
      }
      setPublishMessage("Recap published to Campaign Wiki.");
    } catch (err) {
      onSetError(err.message);
    } finally {
      onSetSaving(false);
    }
  }

  async function handleGenerateRecap() {
    if (!selectedSession) return;
    setAiSessionLoading(true);
    setAiSessionError(null);
    setAiSessionProgress("Gathering session data...");

    try {
      const res = await fetch("/api/ai/session-recap", {
        method: "POST",
        headers: authHeaders,
        body: JSON.stringify({ sessionId: selectedSession.id }),
      });

      const contentType = res.headers.get("content-type") || "";
      if (!contentType.includes("text/event-stream")) {
        if (!res.ok) {
          const err = await res.json().catch(() => ({}));
          throw new Error(err.error || "Failed to generate recap.");
        }
      }

      if (!res.ok || !res.body) {
        throw new Error("Failed to start recap stream.");
      }

      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      let resultText = null;

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() || "";
        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          const payload = line.slice(6).trim();
          if (!payload) continue;
          try {
            const event = JSON.parse(payload);
            if (event.type === "status") setAiSessionProgress(event.message);
            if (event.type === "result") resultText = event.data;
            if (event.type === "error") throw new Error(event.message);
          } catch (e) {
            if (e.message) throw e;
          }
        }
      }

      if (resultText) {
        onUpdateField("recap", resultText);
        await onPatchSession({ recap: resultText });
      } else {
        throw new Error("No recap text received.");
      }
    } catch (err) {
      setAiSessionError(err.message);
    } finally {
      setAiSessionLoading(false);
      setAiSessionProgress("");
    }
  }

  async function handleGenerateAgenda() {
    if (!selectedSession) return;
    setAiSessionLoading(true);
    setAiSessionError(null);
    setAiSessionProgress("Analyzing campaign state...");

    try {
      const res = await fetch("/api/ai/session-agenda", {
        method: "POST",
        headers: authHeaders,
        body: JSON.stringify({ sessionId: selectedSession.id }),
      });

      const contentType = res.headers.get("content-type") || "";
      if (!contentType.includes("text/event-stream")) {
        if (!res.ok) {
          const err = await res.json().catch(() => ({}));
          throw new Error(err.error || "Failed to generate agenda.");
        }
      }

      if (!res.ok || !res.body) {
        throw new Error("Failed to start agenda stream.");
      }

      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      let resultText = null;

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() || "";
        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          const payload = line.slice(6).trim();
          if (!payload) continue;
          try {
            const event = JSON.parse(payload);
            if (event.type === "status") setAiSessionProgress(event.message);
            if (event.type === "result") resultText = event.data;
            if (event.type === "error") throw new Error(event.message);
          } catch (e) {
            if (e.message) throw e;
          }
        }
      }

      if (resultText) {
        onUpdateField("agenda", resultText);
        await onPatchSession({ agenda: resultText });
      } else {
        throw new Error("No agenda text received.");
      }
    } catch (err) {
      setAiSessionError(err.message);
    } finally {
      setAiSessionLoading(false);
      setAiSessionProgress("");
    }
  }

  /* ---- linked resources ---- */
  function renderLinkedResources() {
    const linkedWikiIds = parseIdArray(selectedSession.linkedWikiIds);
    const linkedMapIds = parseIdArray(selectedSession.linkedMapIds);
    const linkedEncounterIds = parseIdArray(selectedSession.linkedEncounterIds);

    const visibleWikiIds = isDm
      ? linkedWikiIds
      : linkedWikiIds.filter((wikiId) => wikiById.get(wikiId)?.isVisibleToPlayers);

    if (!isDm && !visibleWikiIds.length && !linkedMapIds.length && !linkedEncounterIds.length) {
      return <p style={sessionStyles.mutedText}>No linked resources for this session.</p>;
    }

    return (
      <div style={sessionStyles.linkedGroups}>
        {visibleWikiIds.length > 0 && (
          <div style={sessionStyles.linkedGroup}>
            <div style={sessionStyles.linkedGroupTitle}>Wiki Articles</div>
            {visibleWikiIds.map((wikiId) => {
              const article = wikiById.get(wikiId);
              return (
                <button
                  key={`wiki-${wikiId}`}
                  type="button"
                  style={sessionStyles.linkedItem}
                  className="touch-target"
                  onClick={() => navigate(isDm ? "/dm/wiki" : "/player/wiki")}
                >
                  <Link2 size={14} />
                  <span>{article?.title || `Wiki #${wikiId}`}</span>
                </button>
              );
            })}
          </div>
        )}

        {isDm && linkedMapIds.length > 0 && (
          <div style={sessionStyles.linkedGroup}>
            <div style={sessionStyles.linkedGroupTitle}>Maps</div>
            {linkedMapIds.map((mapId) => {
              const mapItem = mapById.get(mapId);
              return (
                <button
                  key={`map-${mapId}`}
                  type="button"
                  style={sessionStyles.linkedItem}
                  className="touch-target"
                  onClick={() => navigate("/dm/map")}
                >
                  <Link2 size={14} />
                  <span>{mapItem?.name || `Map #${mapId}`}</span>
                </button>
              );
            })}
          </div>
        )}

        {isDm && linkedEncounterIds.length > 0 && (
          <div style={sessionStyles.linkedGroup}>
            <div style={sessionStyles.linkedGroupTitle}>Encounters</div>
            {linkedEncounterIds.map((encounterId) => {
              const encounter = encounterById.get(encounterId);
              return (
                <button
                  key={`encounter-${encounterId}`}
                  type="button"
                  style={sessionStyles.linkedItem}
                  className="touch-target"
                  onClick={() => navigate("/dm/map")}
                >
                  <Link2 size={14} />
                  <span>
                    {encounter?.name || `Encounter #${encounterId}`}
                    {encounter?.status ? ` (${encounter.status})` : ""}
                  </span>
                </button>
              );
            })}
          </div>
        )}
      </div>
    );
  }

  function renderLinkPickers() {
    if (!isDm) return null;

    const linkedWikiIds = parseIdArray(selectedSession.linkedWikiIds);
    const linkedMapIds = parseIdArray(selectedSession.linkedMapIds);
    const linkedEncounterIds = parseIdArray(selectedSession.linkedEncounterIds);

    return (
      <div style={sessionStyles.pickerSection}>
        <h4 style={sessionStyles.sectionTitle}>Link Prep Resources</h4>

        <div style={sessionStyles.pickerGroup}>
          <div style={sessionStyles.pickerLabel}>Wiki Articles</div>
          <div style={sessionStyles.pickerList}>
            {wikiArticles.length === 0 ? (
              <span style={sessionStyles.mutedText}>No wiki articles yet.</span>
            ) : (
              wikiArticles.map((article) => (
                <label key={article.id} style={sessionStyles.pickerItem} className="touch-target">
                  <input
                    type="checkbox"
                    checked={linkedWikiIds.includes(article.id)}
                    onChange={() => toggleLinkedId("linkedWikiIds", article.id)}
                    disabled={saving}
                  />
                  <span>{article.title}</span>
                </label>
              ))
            )}
          </div>
        </div>

        <div style={sessionStyles.pickerGroup}>
          <div style={sessionStyles.pickerLabel}>Maps</div>
          <div style={sessionStyles.pickerList}>
            {maps.length === 0 ? (
              <span style={sessionStyles.mutedText}>No maps yet.</span>
            ) : (
              maps.map((mapItem) => (
                <label key={mapItem.id} style={sessionStyles.pickerItem} className="touch-target">
                  <input
                    type="checkbox"
                    checked={linkedMapIds.includes(mapItem.id)}
                    onChange={() => toggleLinkedId("linkedMapIds", mapItem.id)}
                    disabled={saving}
                  />
                  <span>{mapItem.name}</span>
                </label>
              ))
            )}
          </div>
        </div>

        <div style={sessionStyles.pickerGroup}>
          <div style={sessionStyles.pickerLabel}>Encounters</div>
          <div style={sessionStyles.pickerList}>
            {encounters.length === 0 ? (
              <span style={sessionStyles.mutedText}>No encounters yet.</span>
            ) : (
              encounters.map((encounter) => (
                <label key={encounter.id} style={sessionStyles.pickerItem} className="touch-target">
                  <input
                    type="checkbox"
                    checked={linkedEncounterIds.includes(encounter.id)}
                    onChange={() => toggleLinkedId("linkedEncounterIds", encounter.id)}
                    disabled={saving}
                  />
                  <span>
                    {encounter.name} ({encounter.status})
                  </span>
                </label>
              ))
            )}
          </div>
        </div>
      </div>
    );
  }

  /* ---- main render ---- */
  const checklistItems = getChecklistItems();
  const progress = checklistProgress(selectedSession.prepChecklist);

  return (
    <div style={sessionStyles.detailPanel}>
      <div style={sessionStyles.detailHeader}>
        <button
          type="button"
          onClick={() => navigate(basePath)}
          style={sessionStyles.backBtn}
          className="touch-target"
        >
          <ArrowLeft size={18} />
          <span>All Sessions</span>
        </button>

        {isDm && (
          <button
            type="button"
            onClick={onDeleteSession}
            style={sessionStyles.deleteBtn}
            className="touch-target"
            disabled={saving}
          >
            <Trash2 size={16} />
          </button>
        )}
      </div>

      <div style={sessionStyles.detailMeta}>
        {isDm ? (
          <>
            <input
              type="text"
              value={selectedSession.title}
              onChange={(e) => onUpdateField("title", e.target.value)}
              onBlur={() => onPatchSession({ title: selectedSession.title })}
              style={sessionStyles.titleInput}
              className="form-input"
              disabled={saving}
            />
            <div style={sessionStyles.metaRow}>
              <label style={sessionStyles.metaField}>
                <span>Session #</span>
                <input
                  type="number"
                  min="1"
                  value={selectedSession.sessionNumber ?? ""}
                  onChange={(e) =>
                    onUpdateField(
                      "sessionNumber",
                      e.target.value ? Number(e.target.value) : null
                    )
                  }
                  onBlur={() =>
                    onPatchSession({ sessionNumber: selectedSession.sessionNumber })
                  }
                  style={sessionStyles.numberInput}
                  className="form-input"
                  disabled={saving}
                />
              </label>
              <label style={sessionStyles.metaField}>
                <span>Play Date</span>
                <input
                  type="date"
                  value={toDateInputValue(selectedSession.scheduledFor)}
                  onChange={(e) =>
                    onUpdateField(
                      "scheduledFor",
                      e.target.value ? new Date(e.target.value).toISOString() : null
                    )
                  }
                  onBlur={() =>
                    onPatchSession({ scheduledFor: selectedSession.scheduledFor })
                  }
                  style={sessionStyles.dateInput}
                  className="form-input"
                  disabled={saving}
                />
              </label>
            </div>
          </>
        ) : (
          <>
            <h2 style={sessionStyles.detailTitle}>
              {selectedSession.sessionNumber
                ? `Session ${selectedSession.sessionNumber}: `
                : ""}
              {selectedSession.title}
            </h2>
            {selectedSession.scheduledFor && (
              <p style={sessionStyles.dateLine}>{formatDate(selectedSession.scheduledFor)}</p>
            )}
          </>
        )}

        <div style={sessionStyles.statusBadgeRow}>
          <span style={{ ...sessionStyles.statusBadge, ...statusStyle(selectedSession.status) }}>
            {selectedSession.status}
          </span>
          {isDm && (
            <label style={sessionStyles.visibilityToggle} className="touch-target">
              <input
                type="checkbox"
                checked={selectedSession.isVisibleToPlayers}
                onChange={(e) => onPatchSession({ isVisibleToPlayers: e.target.checked })}
                disabled={saving}
              />
              {selectedSession.isVisibleToPlayers ? <Eye size={16} /> : <EyeOff size={16} />}
              <span>Visible to Players</span>
            </label>
          )}
        </div>
      </div>

      {isDm && (
        <div style={sessionStyles.lifecycleRow}>
          {selectedSession.status === "PLANNED" && (
            <button
              type="button"
              style={sessionStyles.primaryBtn}
              className="touch-target"
              onClick={() => onPatchSession({ status: "ACTIVE" })}
              disabled={saving}
            >
              Start Session
            </button>
          )}
          {selectedSession.status === "ACTIVE" && (
            <button
              type="button"
              style={sessionStyles.primaryBtn}
              className="touch-target"
              onClick={() => onPatchSession({ status: "COMPLETED" })}
              disabled={saving}
            >
              End Session
            </button>
          )}
          {selectedSession.status === "COMPLETED" && (
            <button
              type="button"
              style={sessionStyles.secondaryBtn}
              className="touch-target"
              onClick={() => onPatchSession({ status: "PLANNED" })}
              disabled={saving}
            >
              Reopen as Planned
            </button>
          )}
        </div>
      )}

      {aiSessionProgress && <p style={sessionStyles.mutedText}>{aiSessionProgress}</p>}
      {aiSessionError && <p style={sessionStyles.errorText}>{aiSessionError}</p>}

      {(selectedSession.status === "PLANNED" || selectedSession.status === "ACTIVE") && (
        <section style={sessionStyles.section}>
          <div style={sessionStyles.sectionHeaderRow}>
            <h3 style={sessionStyles.sectionTitle}>Agenda</h3>
            {isDm && (
              <button
                type="button"
                style={sessionStyles.togglePreviewBtn}
                className="touch-target"
                onClick={() => setShowPreview((prev) => !prev)}
              >
                {showPreview ? "Edit" : "Preview"}
              </button>
            )}
          </div>
          {isDm && !showPreview ? (
            <>
              <div style={{ display: "flex", gap: "0.5rem", marginBottom: "0.5rem", flexWrap: "wrap", alignItems: "center" }}>
                <AiAssistButton
                  fieldName="agenda"
                  actions={AI_FIELD_ACTIONS.agenda}
                  currentText={selectedSession?.agenda || ""}
                  context={{ entityType: "session", session: { title: selectedSession?.title, status: selectedSession?.status, agenda: selectedSession?.agenda } }}
                  onApply={(reply) => {
                    onUpdateField("agenda", reply);
                    onPatchSession({ agenda: reply });
                  }}
                  onError={(msg) => setAiSessionError(msg)}
                  user={user}
                />
                <button
                  type="button"
                  onClick={handleGenerateAgenda}
                  disabled={aiSessionLoading}
                  style={{
                    padding: "0.35rem 0.65rem", fontSize: "0.75rem", borderRadius: "4px",
                    border: "1px solid rgba(200, 151, 58, 0.3)",
                    background: "rgba(200, 151, 58, 0.1)", color: "var(--color-accent)",
                    cursor: "pointer", whiteSpace: "nowrap",
                    opacity: aiSessionLoading ? 0.6 : 1,
                  }}
                  className="touch-target"
                >
                  {aiSessionLoading ? "..." : "✨ AI Suggest Agenda"}
                </button>
              </div>
              <textarea
                value={selectedSession.agenda}
                onChange={(e) => onUpdateField("agenda", e.target.value)}
                onBlur={() => onPatchSession({ agenda: selectedSession.agenda })}
                style={sessionStyles.textarea}
                className="form-input"
                placeholder="Scene plan, beats, NPC notes..."
                disabled={saving}
              />
            </>
          ) : (
            <div
              className="wiki-content"
              style={sessionStyles.markdownPreview}
              dangerouslySetInnerHTML={{
                __html: compileMarkdown(selectedSession.agenda || "_No agenda yet._"),
              }}
            />
          )}
        </section>
      )}

      {(selectedSession.status === "PLANNED" || selectedSession.status === "ACTIVE") && (
        <section style={sessionStyles.section}>
          <h3 style={sessionStyles.sectionTitle}>
            Prep Checklist {progress.total ? `(${progress.done}/${progress.total})` : ""}
          </h3>
          <div style={sessionStyles.checklist}>
            {checklistItems.map((item) => (
              <div key={item.id} style={sessionStyles.checklistItem}>
                <button
                  type="button"
                  style={{
                    ...sessionStyles.checkBtn,
                    ...(item.done ? sessionStyles.checkBtnDone : {}),
                  }}
                  className="touch-target"
                  onClick={() => isDm && handleToggleChecklistItem(item.id)}
                  disabled={!isDm || saving}
                >
                  {item.done && <Check size={14} />}
                </button>
                <span style={{ ...sessionStyles.checklistText, ...(item.done ? sessionStyles.checklistDone : {}) }}>
                  {item.text}
                </span>
                {isDm && (
                  <button
                    type="button"
                    style={sessionStyles.removeCheckBtn}
                    className="touch-target"
                    onClick={() => handleRemoveChecklistItem(item.id)}
                    disabled={saving}
                  >
                    <X size={14} />
                  </button>
                )}
              </div>
            ))}
          </div>
          {isDm && (
            <form onSubmit={handleAddChecklistItem} style={sessionStyles.addChecklistForm}>
              <input
                type="text"
                value={newChecklistItem}
                onChange={(e) => setNewChecklistItem(e.target.value)}
                placeholder="Add prep task..."
                style={sessionStyles.checklistInput}
                className="form-input"
                disabled={saving}
              />
              <button type="submit" style={sessionStyles.secondaryBtn} className="touch-target" disabled={saving}>
                <Plus size={16} />
              </button>
            </form>
          )}
        </section>
      )}

      {(selectedSession.status === "PLANNED" || selectedSession.status === "ACTIVE") && (
        <section style={sessionStyles.section}>
          <h3 style={sessionStyles.sectionTitle}>Linked Resources</h3>
          {renderLinkedResources()}
          {renderLinkPickers()}
        </section>
      )}

      {(selectedSession.status === "COMPLETED" || selectedSession.recap) && (
        <section style={sessionStyles.section}>
          <div style={sessionStyles.sectionHeaderRow}>
            <h3 style={sessionStyles.sectionTitle}>Session Recap</h3>
            {isDm && selectedSession.wikiLogId && (
              <button
                type="button"
                style={sessionStyles.linkBtn}
                className="touch-target"
                onClick={() => navigate("/dm/wiki")}
              >
                View Wiki Log
              </button>
            )}
          </div>
          {isDm ? (
            <>
              <div style={{ display: "flex", gap: "0.5rem", marginBottom: "0.5rem", flexWrap: "wrap", alignItems: "center" }}>
                <AiAssistButton
                  fieldName="recap"
                  actions={AI_FIELD_ACTIONS.recap}
                  currentText={selectedSession?.recap || ""}
                  context={{ entityType: "session", session: { title: selectedSession?.title, status: selectedSession?.status, agenda: selectedSession?.agenda } }}
                  onApply={(reply) => {
                    onUpdateField("recap", reply);
                    onPatchSession({ recap: reply });
                  }}
                  onError={(msg) => setAiSessionError(msg)}
                  user={user}
                />
                <button
                  type="button"
                  onClick={handleGenerateRecap}
                  disabled={aiSessionLoading}
                  style={{
                    padding: "0.35rem 0.65rem", fontSize: "0.75rem", borderRadius: "4px",
                    border: "1px solid rgba(200, 151, 58, 0.3)",
                    background: "rgba(200, 151, 58, 0.1)", color: "var(--color-accent)",
                    cursor: "pointer", whiteSpace: "nowrap",
                    opacity: aiSessionLoading ? 0.6 : 1,
                  }}
                  className="touch-target"
                >
                  {aiSessionLoading ? "..." : "✨ AI Write Recap"}
                </button>
              </div>
              <textarea
                value={selectedSession.recap}
                onChange={(e) => onUpdateField("recap", e.target.value)}
                onBlur={() => onPatchSession({ recap: selectedSession.recap })}
                style={sessionStyles.textarea}
                className="form-input"
                placeholder="What happened, loot awarded, hooks for next time..."
                disabled={saving}
              />
              <button
                type="button"
                style={sessionStyles.primaryBtn}
                className="touch-target"
                onClick={handlePublishRecap}
                disabled={saving || !selectedSession.recap.trim()}
              >
                Publish to Wiki
              </button>
              {publishMessage && <p style={sessionStyles.successText}>{publishMessage}</p>}
            </>
          ) : (
            <div
              className="wiki-content"
              style={sessionStyles.markdownPreview}
              dangerouslySetInnerHTML={{
                __html: compileMarkdown(selectedSession.recap || "_No recap published yet._"),
              }}
            />
          )}
          {!isDm && selectedSession.wikiLogId && (
            <button
              type="button"
              style={sessionStyles.linkBtn}
              className="touch-target"
              onClick={() => navigate("/player/wiki")}
            >
              Read Full Session Log
            </button>
          )}
        </section>
      )}

      {saving && <p style={sessionStyles.mutedText}>Saving...</p>}
    </div>
  );
}

