// Tablecast — Wiki Panel Utility Functions (Extracted from WikiPanel)
// Pure utility functions for D&D 5e data formatting and markdown rendering
// =============================================================================
import { marked } from "marked";
import DOMPurify from "dompurify";

/**
 * Calculate ability modifier from a D&D 5e ability score (0-30).
 * @param {number} score - Ability score (defaults to 10)
 * @returns {string} Formatted modifier like "+3" or "-1"
 */
export function calculateModifier(score) {
  const mod = Math.floor((Number(score || 10) - 10) / 2);
  return mod >= 0 ? `+${mod}` : `${mod}`;
}

/**
 * Build an image generation prompt from NPC data for AI art tools.
 * Combines name, race, class, alignment, appearance, personality,
 * description, and equipment into a detailed prompt string.
 * @param {object} npc - NPC or Monster data object
 * @param {string} styleSuffix - Optional DM-configured style suffix
 * @returns {string} Combined prompt string
 */
export function buildImagePrompt(npc, styleSuffix = "") {
  const parts = [];
  // Core identity
  parts.push(`Fantasy portrait of ${npc.name || "an NPC"}`);
  if (npc.race) parts.push(`a ${npc.race}`);
  if (npc.class) parts.push(`${npc.class}`);
  // Alignment / vibe
  if (npc.alignment) parts.push(`with a ${npc.alignment.toLowerCase()} alignment`);
  // Appearance (strip markdown for cleaner prompt)
  if (npc.appearance) {
    const clean = npc.appearance.replace(/[*#>`_~\[\]]/g, "").trim();
    if (clean) parts.push(clean);
  }
  // Personality flavour
  if (npc.personality) {
    const clean = npc.personality.replace(/[*#>`_~\[\]]/g, "").trim().slice(0, 160);
    if (clean) parts.push(`Personality: ${clean}`);
  }
  // Description / location hints
  if (npc.description) {
    const clean = npc.description.replace(/[*#>`_~\[\]]/g, "").trim().slice(0, 200);
    if (clean) parts.push(clean);
  }
  // Gear / equipment from actions
  if (npc.actions) {
    try {
      const actions = JSON.parse(npc.actions);
      const weaponNames = actions.map(a => a.name).filter(Boolean).slice(0, 3);
      if (weaponNames.length > 0) {
        parts.push(`wielding ${weaponNames.join(", ")}`);
      }
    } catch (e) {
      // Silently ignore unparseable actions
    }
  }
  // Default style qualifier
  parts.push("D&D 5e character art, detailed fantasy illustration, full body portrait, professional lighting");
  // Append DM's custom style suffix from settings (if any)
  if (styleSuffix) {
    parts.push(styleSuffix);
  }
  return parts.join(", ");
}

/**
 * Compile Markdown text into safe HTML.
 * Uses `marked` for parsing and DOMPurify for XSS prevention.
 * @param {string} markdownText - Raw markdown text
 * @returns {string} Sanitized HTML string
 */
export function compileMarkdown(markdownText) {
  if (!markdownText) return "";
  try {
    const rawHtml = marked.parse(markdownText);
    return DOMPurify.sanitize(rawHtml);
  } catch (e) {
    console.error("[WikiPanel] Markdown parsing failed:", e);
    return "<p style='color:var(--color-danger);'>Failed to parse content.</p>";
  }
}

/**
 * Parse 5eTools alignment format into a human-readable string.
 * Handles arrays of alignment objects, single-letter codes (L, C, G, E, N, A, U),
 * and raw alignment strings.
 * @param {string|Array} alignment - Raw alignment from 5eTools data
 * @returns {string} Human-readable alignment like "Lawful Good" or "Unaligned"
 */
export function parse5eToolsAlignment(alignment) {
  if (!alignment) return "Unaligned";
  if (typeof alignment === "string") return alignment;
  if (!Array.isArray(alignment)) return "Unaligned";

  const codes = alignment.map(item => {
    if (typeof item === "string") return item;
    if (item && typeof item === "object" && Array.isArray(item.alignment)) {
      return item.alignment;
    }
    return "";
  }).flat().filter(Boolean);

  if (codes.length === 0) return "Unaligned";
  if (codes.includes("A")) return "Any alignment";
  if (codes.includes("U")) return "Unaligned";

  const mapping = {
    L: "Lawful",
    C: "Chaotic",
    G: "Good",
    E: "Evil",
    N: "Neutral"
  };

  if (codes.length === 1 && codes[0] === "N") return "Neutral";

  const words = codes.map(c => mapping[c] || c);
  return words.join(" ");
}

// =============================================================================
// Tablecast — Promise-based Confirmation Dialog Context
// Replaces native confirm() with a styled, non-blocking modal dialog.
// Usage: const { showConfirm } = useConfirm();
//        if (await showConfirm("Delete?", "Are you sure?")) { ... }
// =============================================================================
import { createContext, useContext, useState, useCallback, useRef, useEffect } from "react";

const ConfirmContext = createContext(null);

export function useConfirm() {
  const ctx = useContext(ConfirmContext);
  if (!ctx) throw new Error("useConfirm must be used within a ConfirmProvider");
  return ctx;
}

export function ConfirmProvider({ children }) {
  const [state, setState] = useState(null); // { title, message, confirmLabel } or null
  const resolveRef = useRef(null);

  const showConfirm = useCallback((...args) => {
    let title; let message; let confirmLabel;
    if (args.length === 1) {
      title = "Confirm";
      message = args[0];
      confirmLabel = "Confirm";
    } else if (args.length === 2 && typeof args[1] === "string") {
      title = args[0];
      message = args[1];
      confirmLabel = title.replace(/[?]$/, "");
    } else {
      title = args[0];
      message = args[1];
      confirmLabel = args[2] ?? title.replace(/[?]$/, "");
    }

    return new Promise((resolve) => {
      resolveRef.current = resolve;
      setState({ title, message, confirmLabel });
    });
  }, []);

  const handleConfirm = useCallback(() => {
    if (resolveRef.current) {
      resolveRef.current(true);
      resolveRef.current = null;
      setState(null);
    }
  }, []);

  const handleCancel = useCallback(() => {
    if (resolveRef.current) {
      resolveRef.current(false);
      resolveRef.current = null;
      setState(null);
    }
  }, []);

  // Escape key dismisses
  useEffect(() => {
    if (!state) return;
    const onKey = (e) => {
      if (e.key === "Escape") handleCancel();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [state, handleCancel]);

  return (
    <ConfirmContext.Provider value={{ showConfirm }}>
      {children}
      {state && (
        <div
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(5, 3, 10, 0.8)",
            backdropFilter: "blur(6px)",
            WebkitBackdropFilter: "blur(6px)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 10000,
            padding: "1rem",
          }}
          onClick={handleCancel}
        >
          <div
            className="glass-panel gold-border-glow"
            style={{
              width: "100%",
              maxWidth: "400px",
              borderRadius: "10px",
              padding: "1.25rem",
              display: "flex",
              flexDirection: "column",
              gap: "1rem",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <h3
              style={{
                fontSize: "1rem",
                fontWeight: 700,
                color: "var(--color-danger)",
                margin: 0,
                borderBottom: "1px solid rgba(255,255,255,0.06)",
                paddingBottom: "0.5rem",
              }}
            >
              {state.title}
            </h3>
            <p
              style={{
                fontSize: "0.85rem",
                lineHeight: 1.5,
                color: "var(--color-text)",
                margin: 0,
              }}
            >
              {state.message}
            </p>
            <div
              style={{
                display: "flex",
                justifyContent: "flex-end",
                gap: "0.5rem",
                borderTop: "1px solid rgba(255,255,255,0.06)",
                paddingTop: "0.75rem",
              }}
            >
              <button
                onClick={handleCancel}
                className="touch-target"
                style={{
                  padding: "0.45rem 0.85rem",
                  borderRadius: "4px",
                  background: "transparent",
                  border: "1px solid rgba(255,255,255,0.1)",
                  color: "var(--color-text)",
                  cursor: "pointer",
                  fontSize: "0.75rem",
                  fontWeight: 600,
                  minWidth: "80px",
                }}
              >
                Cancel
              </button>
              <button
                onClick={handleConfirm}
                className="touch-target btn-hover-scale"
                style={{
                  padding: "0.45rem 1rem",
                  borderRadius: "4px",
                  background: "rgba(235, 87, 87, 0.15)",
                  border: "1px solid rgba(235, 87, 87, 0.35)",
                  color: "var(--color-danger)",
                  cursor: "pointer",
                  fontSize: "0.75rem",
                  fontWeight: 700,
                  minWidth: "80px",
                }}
              >
                {state.confirmLabel}
              </button>
            </div>
          </div>
        </div>
      )}
    </ConfirmContext.Provider>
  );
}

import { createContext, useContext, useEffect, useRef, useState, useCallback } from "react";
import DiceBox from "@3d-dice/dice-box";

const debug = typeof import.meta !== "undefined" && import.meta.env?.DEV ? console.log : () => {};

const DiceBoxContext = createContext(null);

// Fallback random generator when 3D dice box is unavailable
function fallbackRoll(notation) {
  const groups = [];
  const allRolls = [];
  let total = 0;

  const parseNotation = (str) => {
    const match = str.match(/^(\d+)[dD](\d+)(?:([+-])(\d+))?$/);
    if (!match) return null;
    return {
      qty: parseInt(match[1], 10),
      sides: parseInt(match[2], 10),
      modifier: match[3] === "-" ? -parseInt(match[4] || 0, 10) : parseInt(match[4] || 0, 10),
    };
  };

  const items = Array.isArray(notation) ? notation : [notation];
  for (const item of items) {
    const parsed = parseNotation(item);
    if (!parsed) continue;
    const rollValues = [];
    for (let i = 0; i < parsed.qty; i++) {
      rollValues.push(Math.floor(Math.random() * parsed.sides) + 1);
    }
    const groupSum = rollValues.reduce((a, b) => a + b, 0) + parsed.modifier;
    const group = {
      qty: parsed.qty,
      sides: parsed.sides,
      modifier: parsed.modifier,
      value: groupSum,
      rolls: rollValues.map((v) => ({ value: v, sides: parsed.sides, qty: 1 })),
    };
    groups.push(group);
    allRolls.push(...rollValues);
    total += groupSum;
  }

  return { groups, allRolls, total };
}

export function DiceBoxProvider({ children }) {
  const containerRef = useRef(null);
  const diceBoxRef = useRef(null);
  const [isReady, setIsReady] = useState(false);
  const [isRolling, setIsRolling] = useState(false);
  const isRollingRef = useRef(false);
  const clearTimeoutRef = useRef(null);
  // Keep queue in state to trigger re-renders when queue changes
  const [queue, setQueue] = useState([]);
  const queueRef = useRef([]);
  // Pending promise resolve/reject for the active roll
  const pendingResolve = useRef(null);
  const pendingReject = useRef(null);
  const mountedRef = useRef(true);

  useEffect(() => {
    mountedRef.current = true;
    if (!containerRef.current) return;

    // Initialize the DiceBox instance
    const box = new DiceBox({
      container: "#dice-box-canvas",
      id: "dice-canvas",
      assetPath: "/assets/dice-box/", // Must match public folder structure
      theme: "default",
      offscreen: false, // Keep on UI thread for maximum compatibility on mobile
      gravity: 3,
      mass: 1,
      friction: 0.8,
      restitution: 0.1,
    });

    box.init().then(() => {
      if (!mountedRef.current) return;
      diceBoxRef.current = box;
      setIsReady(true);
      debug("[3D Dice] DiceBox initialized successfully.");

      // Force an immediate window resize event to trigger correct layout size calculations
      window.dispatchEvent(new Event("resize"));

      // Setup global complete listener — resolves pending roll promise with physics results
      box.onRollComplete = (results) => {
        debug("[3D Dice] Roll complete:", results);

        // Extract flat roll values from the grouped results
        const allRolls = [];
        let total = 0;
        for (const group of results) {
          if (group.rolls) {
            for (const die of group.rolls) {
              allRolls.push(die.value);
            }
          }
          total += group.value || 0;
        }

        // Resolve the pending promise so the caller gets the actual physics results
        if (pendingResolve.current) {
          pendingResolve.current({ groups: results, allRolls, total });
          pendingResolve.current = null;
          pendingReject.current = null;
        }

        // Remove completed roll from queue
        queueRef.current.shift();
        setQueue([...queueRef.current]);

        // Delay clearing/hiding dice slightly for better visual polish
        clearTimeoutRef.current = setTimeout(() => {
          if (!mountedRef.current) return;
          if (diceBoxRef.current) {
            diceBoxRef.current.clear();
          }
          isRollingRef.current = false;
          setIsRolling(false);
        }, 1200);
      };
    }).catch(err => {
      if (!mountedRef.current) return;
      console.error("[3D Dice] Failed to initialize DiceBox:", err);
    });

    return () => {
      mountedRef.current = false;
      if (clearTimeoutRef.current) {
        clearTimeout(clearTimeoutRef.current);
      }
      if (diceBoxRef.current) {
        diceBoxRef.current.clear();
        diceBoxRef.current = null;
      }
    };
  }, []);

  // Process the queue — one roll at a time
  useEffect(() => {
    if (!isReady || isRollingRef.current || queue.length === 0) return;

    const nextRoll = queue[0];
    isRollingRef.current = true;
    setIsRolling(true);

    const { notation, theme, color, resolve, reject } = nextRoll;
    const box = diceBoxRef.current;

    if (box && notation.length > 0) {
      debug("[3D Dice] Rolling:", notation, "with theme:", theme, "and color:", color);

      // Force viewport resize event just in case layout changed before active roll
      window.dispatchEvent(new Event("resize"));

      const activeTheme = theme || "default";
      const rollThemeColor = color || "#7c3aed";

      // Store promise callbacks for onRollComplete to call
      pendingResolve.current = resolve;
      pendingReject.current = reject;

      // Update config with the active theme and color dynamically
      try {
        box.updateConfig({
          theme: activeTheme,
          themeColor: rollThemeColor,
        });
      } catch (err) {
        console.error("[3D Dice] Failed to update config:", err);
      }

      // Ensure the theme is loaded first, then roll
      const loadPromise = typeof box.loadTheme === "function"
        ? box.loadTheme(activeTheme)
        : Promise.resolve();

      loadPromise
        .then(() => box.roll(notation, {
            theme: activeTheme,
            themeColor: rollThemeColor,
          }))
        .catch((err) => {
          console.error("[3D Dice] Roll error:", err);
          if (pendingReject.current) {
            pendingReject.current(err);
            pendingResolve.current = null;
            pendingReject.current = null;
          }
          queueRef.current.shift();
          setQueue([...queueRef.current]);
          isRollingRef.current = false;
          setIsRolling(false);
        });
    } else {
      // Box not available — reject the promise
      if (reject) {
        reject(new Error("Dice box not available"));
      }
      queueRef.current.shift();
      setQueue([...queueRef.current]);
      isRollingRef.current = false;
      setIsRolling(false);
    }
  }, [isReady, isRolling, queue]);

  // Public API: roll dice with simple notation, returns actual physics results
  const rollDice = useCallback(async (notation, options = {}) => {
    const { theme = "default", color = "#7c3aed" } = options;

    // Normalize to array of non-empty strings
    const normalized = Array.isArray(notation)
      ? notation.filter(Boolean)
      : [notation].filter(Boolean);

    if (normalized.length === 0) {
      return { groups: [], allRolls: [], total: 0 };
    }

    // If the 3D box is not available, use fallback random generation
    if (!diceBoxRef.current || !isReady) {
      debug("[3D Dice] Box not ready, using fallback random generation");
      return fallbackRoll(normalized);
    }

    // Queue the roll and return a promise that resolves with physics results
    return new Promise((resolve, reject) => {
      queueRef.current.push({ notation: normalized, theme, color, resolve, reject });
      setQueue([...queueRef.current]);
    });
  }, [isReady]);

  return (
    <DiceBoxContext.Provider value={{ rollDice, isReady, isRolling }}>
      {children}
      {/* Global full-screen canvas overlay */}
      <div
        id="dice-box-canvas"
        ref={containerRef}
        style={{
          position: "fixed",
          top: 0,
          left: 0,
          width: "100vw",
          height: "100vh",
          zIndex: 9999,
          pointerEvents: isRolling ? "auto" : "none",
          transition: "opacity 0.3s ease",
          opacity: isRolling ? 1 : 0,
        }}
      />
    </DiceBoxContext.Provider>
  );
}

export function useDiceBox() {
  const ctx = useContext(DiceBoxContext);
  if (!ctx) {
    throw new Error("useDiceBox must be used inside a <DiceBoxProvider>.");
  }
  return ctx;
}

// =============================================================================
// SoundContext  Ambient soundboard + AudioContext management
// Handles:
//   1. DM-initiated playback commands (play/pause/seek/volume) via socket sync
//   2. Client-side AudioContext for synchronized audio playback
//   3. Multi-client state sync via 'sound:state' and 'sound:sync' socket events
// =============================================================================
import { createContext, useContext, useEffect, useState, useRef, useCallback } from "react";
import { useSocket } from "./SocketContext";

const debug = import.meta.env.DEV ? console.log : () => {};

const SoundContext = createContext(null);

export function SoundProvider({ children }) {
  const { socket } = useSocket();
  const audioContextRef = useRef(null);
  const audioElementRef = useRef(null);
  const [soundState, setSoundState] = useState({
    trackId: null,
    action: "stop",
    position: 0,
    volume: 0.5,
    timestamp: Date.now(),
  });
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTrackId, setCurrentTrackId] = useState(null);
  const [volume, setVolume] = useState(0.5);
  const [error, setError] = useState(null);

  // Initialize AudioContext lazily (required after user gesture)
  const getAudioContext = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || window.webkitAudioContext)();
    }
    if (audioContextRef.current.state === "suspended") {
      audioContextRef.current.resume();
    }
    return audioContextRef.current;
  }, []);

  // Listen for sound:state broadcasts from server (emitted by DM)
  useEffect(() => {
    if (!socket) return;

    const handleSoundState = (state) => {
      debug("[Sound] State update:", state);
      setSoundState(state);
      setVolume(state.volume);

      if (state.action === "play" && state.trackId) {
        setIsPlaying(true);
        setCurrentTrackId(state.trackId);
        setError(null);
      } else if (state.action === "stop") {
        setIsPlaying(false);
        if (audioElementRef.current) {
          audioElementRef.current.pause();
          audioElementRef.current.currentTime = 0;
        }
      } else if (state.action === "seek" && audioElementRef.current) {
        audioElementRef.current.currentTime = state.position;
      }
    };

    socket.on("sound:state", handleSoundState);
    return () => socket.off("sound:state", handleSoundState);
  }, [socket]);

  // Request sync on mount (reconnecting client)
  useEffect(() => {
    if (!socket) return;
    socket.emit("sound:sync");
  }, [socket]);

  // DM functions: emit sound events to sync all clients
  const playTrack = useCallback((trackId) => {
    if (!socket) return;
    const payload = { trackId, action: "play", position: 0, volume };
    socket.emit("sound:play", payload);
  }, [socket, volume]);

  const stopTrack = useCallback(() => {
    if (!socket) return;
    const payload = { trackId: null, action: "stop", position: 0, volume };
    socket.emit("sound:play", payload);
  }, [socket, volume]);

  const seekTrack = useCallback((position) => {
    if (!socket) return;
    const payload = { trackId: currentTrackId, action: "seek", position, volume };
    socket.emit("sound:play", payload);
  }, [socket, currentTrackId, volume]);

  const setVolumeAll = useCallback((newVolume) => {
    setVolume(newVolume);
    if (audioElementRef.current) {
      audioElementRef.current.volume = newVolume;
    }
  }, []);

  const contextValue = {
    soundState,
    isPlaying,
    currentTrackId,
    volume,
    error,
    playTrack,
    stopTrack,
    seekTrack,
    setVolumeAll,
    getAudioContext,
    audioElementRef,
  };

  return (
    <SoundContext.Provider value={contextValue}>
      {children}
    </SoundContext.Provider>
  );
}

export function useSound() {
  const ctx = useContext(SoundContext);
  if (!ctx) {
    throw new Error("useSound() must be used inside a <SoundProvider>.");
  }
  return ctx;
}

// =============================================================================
// Tablecast — useAiChat Hook
// Shared state management hook for AI chat conversations.
// Provides messages, streaming state, send/cancel/retry/clear actions.
// Used by AiPanel, and can be adopted by ChatPanel for AI interactions.
// =============================================================================

import { useState, useRef, useCallback, useEffect } from "react";
import { streamAiChat } from "../utils/aiStream";
import { getJsonAuthHeaders } from "../utils/authHeaders";

/**
 * @param {Object} opts
 * @param {Object} [opts.user]           - User object with .id
 * @param {string} [opts.initialMessage] - Optional initial assistant message
 * @param {number} [opts.npcId]          - NPC ID for roleplay
 * @param {number} [opts.characterId]    - Character ID for context
 * @param {number} [opts.conversationId] - Existing conversation ID to load
 * @returns {Object} { messages, streaming, error, send, cancel, retry, clearMessages, setMessages }
 */
export function useAiChat({
  user,
  initialMessage = "",
  npcId,
  characterId,
  conversationId: initialConversationId,
} = {}) {
  const [messages, setMessages] = useState(
    initialMessage
      ? [{ role: "assistant", text: initialMessage }]
      : []
  );
  const [streaming, setStreaming] = useState(false);
  const [error, setError] = useState(null);
  const [conversationId, setConversationId] = useState(initialConversationId || null);

  // Ref to store the last sent message for retry
  const lastQueryRef = useRef(null);
  // Ref to the cancel function
  const cancelRef = useRef(null);
  // Ref to track if streaming was intentionally cancelled
  const cancelledRef = useRef(false);
  // Ref to track if component is mounted
  const mountedRef = useRef(true);
  // Ref to the current AbortController
  const controllerRef = useRef(null);
  // Ref to keep messages in sync for multi-turn context (used in send callback)
  const messagesRef = useRef(messages);
  useEffect(() => { messagesRef.current = messages; }, [messages]);

  // Cleanup on unmount — abort in-flight request and prevent state updates
  useEffect(() => {
    mountedRef.current = true;
    return () => {
      mountedRef.current = false;
      cancelledRef.current = true;
      if (controllerRef.current) {
        controllerRef.current.abort();
        controllerRef.current = null;
      }
    };
  }, []);

  // Load conversation messages when initialConversationId is provided
  useEffect(() => {
    if (!initialConversationId) return;

    let cancelled = false;

    (async () => {
      try {
        const res = await fetch(`/api/ai/conversations/${initialConversationId}`, {
          headers: getJsonAuthHeaders(user),
        });
        if (!res.ok) return;
        const data = await res.json();
        if (!cancelled && data.messages) {
          setMessages(data.messages.map(m => ({ role: m.role, text: m.text, createdAt: m.createdAt, timestamp: m.createdAt })));
        }
      } catch (err) {
        console.error("[useAiChat] Failed to load conversation:", err);
      }
    })();

    return () => { cancelled = true; };
  }, [initialConversationId, user?.id]);

  const send = useCallback(
    async (text, overrides = {}) => {
      if (!text?.trim() || streaming) return;

      const query = text.trim();
      lastQueryRef.current = query;
      cancelledRef.current = false;

      // Add user message
      const userMsg = { role: "user", text: query };
      setMessages((prev) => [...prev, userMsg]);

      setStreaming(true);
      setError(null);

      let assistantStarted = false;
      let accumulated = "";

      const controller = new AbortController();
      controllerRef.current = controller;
      cancelRef.current = () => controller.abort();

      try {
        // Build multi-turn context from current messages (excluding the system message)
        const history = messagesRef.current
          .filter((m) => m.role !== "system")
          .map((m) => ({ role: m.role, text: m.text }));

        const result = await streamAiChat({
          user,
          message: query,
          history,
          npcId: overrides.npcId ?? npcId,
          characterId: overrides.characterId ?? characterId,
          conversationId: overrides.conversationId ?? conversationId,
          stream: true,
          signal: controller.signal,
          onToken: (token) => {
            if (!mountedRef.current || cancelledRef.current) return;
            accumulated += token;
            setMessages((prev) => {
              if (!assistantStarted) {
                assistantStarted = true;
                return [...prev, { role: "assistant", text: accumulated }];
              }
              const copy = [...prev];
              copy[copy.length - 1] = { role: "assistant", text: accumulated };
              return copy;
            });
          },
        });

        if (!mountedRef.current) return;

        // If server returned a conversationId from auto-save, track it
        if (result?.conversationId) {
          setConversationId(result.conversationId);
        }

        // Attach rollChips to the last assistant message if present
        if (result?.rollChips && result.rollChips.length > 0) {
          setMessages((prev) => {
            const copy = [...prev];
            const last = copy[copy.length - 1];
            if (last && last.role === "assistant") {
              copy[copy.length - 1] = { ...last, rollChips: result.rollChips };
            }
            return copy;
          });
        }
      } catch (err) {
        if (err.name === "AbortError" || !mountedRef.current || cancelledRef.current) return;

        const errorText = err.message || "Connection lost.";
        if (!mountedRef.current) return;
        setError(errorText);

        if (mountedRef.current) {
          setMessages((prev) => {
            if (!assistantStarted) {
              return [...prev, { role: "assistant", text: `Error: ${errorText}` }];
            }
            const copy = [...prev];
            const last = copy[copy.length - 1];
            copy[copy.length - 1] = {
              role: "assistant",
              text: accumulated
                ? `${accumulated}\n\n*Error: ${errorText}*`
                : `Error: ${errorText}`,
            };
            return copy;
          });
        }
      } finally {
        if (mountedRef.current) {
          setStreaming(false);
        }
        cancelRef.current = null;
        controllerRef.current = null;
      }
    },
    [user, streaming, npcId, characterId, conversationId]
  );

  const cancel = useCallback(() => {
    cancelledRef.current = true;
    if (cancelRef.current) {
      cancelRef.current();
      cancelRef.current = null;
    }
    setStreaming(false);
  }, []);

  const retry = useCallback(async () => {
    if (!lastQueryRef.current) return;
    // Remove the last user + assistant messages (if any)
    setMessages((prev) => {
      // Remove last assistant message if it was an error
      const copy = [...prev];
      if (copy.length >= 2 && copy[copy.length - 1].role === "assistant") {
        copy.pop(); // remove assistant error/partial
      }
      if (copy.length >= 1 && copy[copy.length - 1].role === "user") {
        copy.pop(); // remove the user message that triggered the error
      }
      return copy;
    });
    await send(lastQueryRef.current);
  }, [send]);

  const clearMessages = useCallback(
    (newInitialMessage = "") => {
      setMessages(
        newInitialMessage
          ? [{ role: "assistant", text: newInitialMessage }]
          : []
      );
      setError(null);
      lastQueryRef.current = null;
    },
    []
  );

  const loadConversation = useCallback((conv) => {
    setConversationId(conv.id);
    setMessages(
      conv.messages?.map((m) => ({ role: m.role, text: m.text })) || []
    );
    setError(null);
  }, []);

  return {
    messages,
    setMessages,
    streaming,
    error,
    conversationId,
    setConversationId,
    send,
    cancel,
    retry,
    clearMessages,
    loadConversation,
    lastQueryRef,
  };
}

// =============================================================================
// Tablecast — useConversations Hook (Phase 2)
// Extracted from AiPanel to reduce local state count.
// Provides conversation list CRUD: loading, create, delete, load.
// =============================================================================
import { useState, useCallback } from "react";
import { getJsonAuthHeaders } from "../utils/authHeaders";

/**
 * @param {Object} opts
 * @param {Object} [opts.user] - User object with .id
 * @returns {Object} { conversations, loadingConvs, loadConversationList, createConversation, deleteConversation, loadConversation }
 */
export function useConversations({ user } = {}) {
  const [conversations, setConversations] = useState([]);
  const [loadingConvs, setLoadingConvs] = useState(false);

  const loadConversationList = useCallback(async () => {
    setLoadingConvs(true);
    try {
      const res = await fetch("/api/ai/conversations", {
        headers: getJsonAuthHeaders(user),
      });
      if (res.ok) {
        const data = await res.json();
        setConversations(data);
      }
    } catch (err) {
      console.error("[useConversations] Failed to load:", err);
    } finally {
      setLoadingConvs(false);
    }
  }, [user?.id]);

  /**
   * Create a new conversation.
   * @param {"rules"|"npc"} type
   * @param {number} [npcId] - Required if type === "npc"
   * @returns {Promise<Object|null>} The created conversation or null
   */
  const createConversation = useCallback(async (type, npcId) => {
    try {
      const res = await fetch("/api/ai/conversations", {
        method: "POST",
        headers: getJsonAuthHeaders(user),
        body: JSON.stringify({
          type,
          npcId: type === "npc" ? npcId || null : null,
        }),
      });
      if (res.ok) {
        const conv = await res.json();
        await loadConversationList();
        return conv;
      }
    } catch (err) {
      console.error("[useConversations] Failed to create:", err);
    }
    return null;
  }, [user?.id, loadConversationList]);

  /**
   * Delete a conversation by ID.
   * @param {number} convId
   */
  const deleteConversation = useCallback(async (convId) => {
    try {
      const res = await fetch(`/api/ai/conversations/${convId}`, {
        method: "DELETE",
        headers: getJsonAuthHeaders(user),
      });
      if (res.ok) {
        await loadConversationList();
      }
    } catch (err) {
      console.error("[useConversations] Failed to delete:", err);
    }
  }, [user?.id, loadConversationList]);

  /**
   * Load a full conversation (with messages) by ID.
   * @param {number} convId
   * @returns {Promise<Object|null>} The conversation with messages
   */
  const loadConversation = useCallback(async (convId) => {
    try {
      const res = await fetch(`/api/ai/conversations/${convId}`, {
        headers: getJsonAuthHeaders(user),
      });
      if (res.ok) {
        return await res.json();
      }
    } catch (err) {
      console.error("[useConversations] Failed to load conv:", err);
    }
    return null;
  }, [user?.id]);

  return {
    conversations,
    loadingConvs,
    loadConversationList,
    createConversation,
    deleteConversation,
    loadConversation,
  };
}
